// Function to process and send the next batch
function processNextBatch() {
    const queue = context.get('queue');
    let batchSize = 0;
    let batchData = {};

    while (queue.length > 0 && Object.keys(batchData).length < MAX_READINGS && batchSize < MAX_BYTES_PER_INTERVAL) {
        const currentItem = queue[0];
        const deviceName = currentItem.device;

        if (!batchData[deviceName]) {
            batchData[deviceName] = [];
        }

        const reading = currentItem.readings.shift();
        batchData[deviceName].push(reading);
        batchSize += JSON.stringify(reading).length;

        if (currentItem.readings.length === 0) {
            queue.shift(); // Remove the current device if all readings are sent
        }
    }

    context.set('queue', queue);

    if (Object.keys(batchData).length > 0) {
        const msg = {
            topic: 'energy/batch',
            payload: batchData
        };
        node.send(msg);
        node.status({fill:"green", shape:"dot", text:`Sent ${batchSize} bytes`});
    } else {
        node.status({fill:"yellow", shape:"ring", text:"Queue empty"});
    }

    // Always schedule the next batch, even if the queue is currently empty
    setTimeout(() => {
        context.set('isProcessing', false);
        checkAndStartProcessing();
    }, SEND_INTERVAL);
}

// Function to check queue and start processing if necessary
function checkAndStartProcessing() {
    const queue = context.get('queue');
    if (queue.length > 0 && !context.get('isProcessing')) {
